from urllib.parse import urlparse, urljoin
from functools import wraps

from flask import Flask, request, redirect, url_for, session, abort, render_template_string

app = Flask(__name__)
app.secret_key = 'your-secret-key-change-in-production'

USERS = {
    'admin': 'password123',
    'user': 'userpass'
}

ALLOWED_HOSTS = {'localhost', '127.0.0.1'}
ALLOWED_SCHEMES = {'http', 'https', ''}


def is_safe_url(target):
    """
    Validate that the redirect URL is safe (not an open redirect).
    
    A URL is considered safe if:
    - It is a relative URL (no scheme/host), or
    - Its host matches one of the allowed hosts
    - Its scheme is http or https (not javascript:, data:, etc.)
    """
    if not target:
        return False

    # Reject URLs with newlines or carriage returns (header injection)
    if '\n' in target or '\r' in target:
        return False

    # Reject backslash-based bypasses (e.g., \evil.com or \/evil.com)
    if target.startswith('\\'):
        return False

    # Parse the target URL
    parsed = urlparse(target)

    # Check scheme is allowed
    if parsed.scheme and parsed.scheme not in ALLOWED_SCHEMES:
        return False

    # If there's no netloc, it's a relative URL — generally safe
    # But we need to check for protocol-relative URLs like //evil.com
    if not parsed.netloc:
        # Check for protocol-relative URLs
        if target.startswith('//'):
            return False
        return True

    # If there is a netloc, verify it's in our allowed hosts
    # Strip port number for comparison
    host = parsed.netloc.split(':')[0]
    if host not in ALLOWED_HOSTS:
        return False

    return True


def get_safe_redirect_url(target, fallback=None):
    """
    Return the target URL if it's safe, otherwise return the fallback URL.
    """
    if fallback is None:
        fallback = url_for('dashboard')

    if target and is_safe_url(target):
        return target

    return fallback


def login_required(f):
    """
    Decorator that redirects unauthenticated users to the login page,
    preserving the originally requested URL via the 'next' parameter.
    """
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session:
            # Store the intended destination in the 'next' query parameter
            return redirect(url_for('login', next=request.url))
        return f(*args, **kwargs)
    return decorated_function


