@app.route('/login', methods=['GET', 'POST'])
def login():
    """
    Login endpoint that handles authentication and safe redirects.
    """
    if 'username' in session:
        # Already logged in — redirect to intended destination or dashboard
        next_url = request.args.get('next', '')
        return redirect(get_safe_redirect_url(next_url))

    error = None

    if request.method == 'POST':
        username = request.form.get('username', '')
        password = request.form.get('password', '')
        next_url = request.form.get('next', '')

        if username in USERS and USERS[username] == password:
            session['username'] = username

            # Safely redirect to the intended destination
            safe_url = get_safe_redirect_url(next_url)
            return redirect(safe_url)
        else:
            error = 'Invalid username or password.'

    # For GET requests, capture the 'next' parameter to embed in the form
    next_url = request.args.get('next', '')

    # Validate the next_url before even putting it in the form
    if not is_safe_url(next_url):
        next_url = ''

    return render_template_string(LOGIN_TEMPLATE, error=error, next_url=next_url)


@app.route('/logout')
def logout():
    session.pop('username', None)
    return redirect(url_for('login'))


