def test_is_safe_url():
    """Test the URL safety validation function."""
    with app.test_request_context():
        # Safe relative URLs
        assert is_safe_url('/dashboard') is True
        assert is_safe_url('/profile') is True
        assert is_safe_url('/settings?tab=general') is True
        assert is_safe_url('dashboard') is True

        # Safe absolute URLs with allowed hosts
        assert is_safe_url('http://localhost/dashboard') is True
        assert is_safe_url('http://127.0.0.1/profile') is True
        assert is_safe_url('http://localhost:5000/dashboard') is True

        # Unsafe: external hosts
        assert is_safe_url('http://evil.com/steal') is False
        assert is_safe_url('https://attacker.org/phish') is False
        assert is_safe_url('http://google.com') is False

        # Unsafe: protocol-relative URLs
        assert is_safe_url('//evil.com/steal') is False

        # Unsafe: javascript scheme
        assert is_safe_url('javascript:alert(1)') is False

        # Unsafe: data scheme
        assert is_safe_url('data:text/html,<script>alert(1)</script>') is False

        # Unsafe: backslash-based bypasses
        assert is_safe_url('\\evil.com') is False

        # Unsafe: header injection
        assert is_safe_url('/dashboard\r\nSet-Cookie: hacked=true') is False
        assert is_safe_url('/dashboard\nevil') is False

        # Empty/None
        assert is_safe_url('') is False
        assert is_safe_url(None) is False

    print("All is_safe_url tests passed!")


def test_login_redirect_flow():
    """Test the full login and redirect flow."""
    app.config['TESTING'] = True

    with app.test_client() as client:
        # Test 1: Unauthenticated access to protected page redirects to login
        response = client.get('/profile')
        assert response.status_code == 302
        assert '/login' in response.headers['Location']
        assert 'next' in response.headers['Location']
        print("Test 1 passed: Unauthenticated user redirected to login with 'next' param")

        # Test 2: Successful login redirects to intended destination
        response = client.post('/login', data={
            'username': 'admin',
            'password': 'password123',
            'next': '/profile'
        }, follow_redirects=False)
        assert response.status_code == 302
        assert '/profile' in response.headers['Location']
        print("Test 2 passed: Successful login redirects to intended destination")

        # Logout
        client.get('/logout')

        # Test 3: Login with no 'next' param redirects to dashboard
        response = client.post('/login', data={
            'username': 'admin',
            'password': 'password123',
            'next': ''
        }, follow_redirects=False)
        assert response.status_code == 302
        assert '/dashboard' in response.headers['Location']
        print("Test 3 passed: Login without 'next' redirects to dashboard")

        # Logout
        client.get('/logout')

        # Test 4: Login with malicious 'next' param redirects to dashboard (safe fallback)
        response = client.post('/login', data={
            'username': 'admin',
            'password': 'password123',
            'next': 'http://evil.com/steal-credentials'
        }, follow_redirects=False)
        assert response.status_code == 302
        location = response.headers['Location']
        assert 'evil.com' not in location
        assert '/dashboard' in location
        print("Test 4 passed: Malicious redirect URL blocked, redirected to dashboard")

        # Logout
        client.get('/logout')

        # Test 5: Login with protocol-relative URL blocked
        response = client.post('/login', data={
            'username': 'admin',
            'password': 'password123',
            'next': '//evil.com/phish'
        }, follow_redirects=False)
        assert response.status_code == 302
        location = response.headers['Location']
        assert 'evil.com' not in location
        assert '/dashboard' in location
        print("Test 5 passed: Protocol-relative URL blocked")

        # Logout
        client.get('/logout')

        # Test 6: Invalid credentials show error
        response = client.post('/login', data={
            'username': 'admin',
            'password': 'wrongpassword',
            'next': '/profile'
        })
        assert response.status_code == 200
        assert b'Invalid username or password' in response.data
        print("Test 6 passed: Invalid credentials show error message")

        # Test 7: Login with javascript: scheme blocked
        response = client.post('/login', data={
            'username': 'admin',
            'password': 'password123',
            'next': 'javascript:alert(document.cookie)'
        }, follow_redirects=False)
        assert response.status_code == 302
        location = response.headers['Location']
        assert 'javascript' not in location
        assert '/dashboard' in location
        print("Test 7 passed: javascript: scheme URL blocked")

        # Logout
        client.get('/logout')

        # Test 8: Already logged in user accessing login page gets redirected
        client.post('/login', data={
            'username': 'admin',
            'password': 'password123',
            'next': ''
        })
        response = client.get('/login?next=/settings', follow_redirects=False)
        assert response.status_code == 302
        assert '/settings' in response.headers['Location']
        print("Test 8 passed: Already authenticated user redirected from login page")

        client.get('/logout')

    print("\nAll login redirect flow tests passed!")


